import{c as a,a7 as t,y as i,B as r}from"./chunks/framework.3cjvm90C.js";const d=JSON.parse('{"title":"Policy Gradient 策略梯度","description":"介绍策略梯度方法的基本原理与 REINFORCE 算法实现","frontmatter":{"title":"Policy Gradient 策略梯度","description":"介绍策略梯度方法的基本原理与 REINFORCE 算法实现"},"headers":[],"relativePath":"rlwiki/hfrlclass/ch4_pg.md","filePath":"rlwiki/hfrlclass/ch4_pg.md","lastUpdated":1782456021000}'),o={name:"rlwiki/hfrlclass/ch4_pg.md"};function l(n,e,s,g,p,c){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="policy-gradient" tabindex="-1">Policy Gradient <a class="header-anchor" href="#policy-gradient" aria-label="Permalink to “Policy Gradient”">​</a></h1><p><a href="https://huggingface.co/blog/deep-rl-dqn" target="_blank" rel="noreferrer">在上一单元</a>中，我们学习了 Deep Q learning。在这个基于价值的深度强化学习算法中，我们 <strong>使用深度神经网络来为一个状态下每个可能的动作近似不同的 Q 值。</strong></p><p>事实上，截止目前，我们只研究了基于价值的方法， <strong>我们将价值函数估计作为寻找最优策略的中间步骤。</strong></p><img src="https://huggingface.co/blog/assets/70_deep_rl_q_part1/link-value-policy.jpg" alt="链接价值Policy" style="zoom:25%;"><p>因为，在基于价值的方法中，策略 <strong>$π$ 仅因为动作价值估计而存在，因为策略只是一个函数</strong> （例如，贪婪策略），它会选择给定状态下具有最高价值的动作。</p><p>但是，在基于策略的方法中，我们希望直接优化策略<strong>而无需学习价值函数的中间步骤。</strong>我们将学习基于策略的方法，并研究这些方法的一个子集，称为策略梯度**。然后我们将使用 PyTorch 从头开始实施我们的第一个策略梯度算法，称为 Monte Carlo **Reinforce。然后，我们将使用 CartPole-v1 和 PixelCopter 环境测试其稳健性。然后，您将能够针对更高级的环境迭代和改进此实现。</p><img src="https://huggingface.co/blog/assets/85_policy_gradient/envs.gif" alt="环境" style="zoom:33%;"><h2 id="基于策略的方法有哪些" tabindex="-1">基于策略的方法有哪些？ <a class="header-anchor" href="#基于策略的方法有哪些" aria-label="Permalink to “基于策略的方法有哪些？”">​</a></h2><p>强化学习的主要目标是<strong>找到最优策略 $π*$ 使期望累积奖励最大化</strong>。因为强化学习基于<em>奖励假设</em>：所有目标都可以描述为期望累积奖励的最大化。</p><h2 id="基于价值的、基于策略的和演员评论家方法" tabindex="-1">基于价值的、基于策略的和演员评论家方法 <a class="header-anchor" href="#基于价值的、基于策略的和演员评论家方法" aria-label="Permalink to “基于价值的、基于策略的和演员评论家方法”">​</a></h2><p>我们在第一单元学习过，有两种方法来找到（大部分时间是近似的）这个最优策略 $π*$.</p><ul><li><p>在基于价值的方法中，我们学习价值函数。</p></li><li><p>想法是通过最优价值函数导致最优策略 $π*$.</p></li><li><p>目标是<strong>最小化预测值和目标值之间的损失</strong>以逼近真实的动作价值函数。</p></li><li><p>我们有一个策略，但它是隐含的，因为它<strong>是直接从价值函数生成的</strong>。例如，在 Q-Learning 中，我们定义了一个 epsilon-greedy 策略。</p></li><li><p>另一方面，在基于策略的方法中，我们直接学习近似 $π*$ 而无需学习价值函数。</p></li><li><p>这个想法是<strong>参数化策略</strong>。例如，使用神经网络 $π_θ$，该策略将输出动作的概率分布（随机策略）。</p></li></ul><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/stochastic_policy.png" alt="随机策略" style="zoom:25%;"><ul><li>我们的目标是<strong>使用梯度上升最大化参数化策略</strong>。</li><li>为此，我们控制参数 $θ$，这将影响在一个 State 下动作的分配。</li></ul><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/policy_based.png" alt="基于策略" style="zoom:25%;"><ul><li>最后，我们将研究<em>actor-critic</em>，它是基于价值和基于策略的方法的结合。</li></ul><p>因此，由于基于策略的方法，我们可以直接优化我们的策略 $π_θ$ 的输出动作的概率分布 $π_θ(a|s)$ 这会带来最佳的累积回报。为此，我们定义了一个目标函数 $J(θ)$，即期望的累积奖励，我们<strong>要找到θ最大化这个目标函数</strong>。</p><h2 id="基于策略和策略梯度方法的区别" tabindex="-1">基于策略和策略梯度方法的区别 <a class="header-anchor" href="#基于策略和策略梯度方法的区别" aria-label="Permalink to “基于策略和策略梯度方法的区别”">​</a></h2><p>本单元中学习的策略梯度方法是基于策略方法的一个子类。这两种方法的区别<strong>在于我们如何优化参数</strong> $θ$:</p><ul><li>在基于策略的方法中，我们直接搜索最优策略。我们可以通过使用爬山、模拟退火或进化策略等技术最大化目标函数的局部近似来间接实现优化参数 $θ$.</li><li>在策略梯度方法中，因为它是基于策略的方法的子类，我们直接搜索最优策略。但是我们<strong>直接</strong>通过对目标函数 $J(θ)$ 进行梯度上升优化参数<em>θ</em> .</li></ul><h2 id="策略梯度方法的优缺点" tabindex="-1">策略梯度方法的优缺点 <a class="header-anchor" href="#策略梯度方法的优缺点" aria-label="Permalink to “策略梯度方法的优缺点”">​</a></h2><p>在深入研究策略梯度方法的工作原理（目标函数、策略梯度定理、梯度上升等）之前，让我们研究一下基于策略的方法的优缺点。</p><h3 id="策略梯度方法的优点" tabindex="-1">策略梯度方法的优点 <a class="header-anchor" href="#策略梯度方法的优点" aria-label="Permalink to “策略梯度方法的优点”">​</a></h3><p>与 Deep Q learning 方法相比有很多优势：</p><h4 id="_1-集成的简单性" tabindex="-1">1. 集成的简单性 <a class="header-anchor" href="#_1-集成的简单性" aria-label="Permalink to “1. 集成的简单性”">​</a></h4><p>可以直接估计策略而无需存储额外的数据（动作值）</p><h4 id="_2-策略梯度方法可以学习随机策略" tabindex="-1">2. 策略梯度方法可以学习随机策略 <a class="header-anchor" href="#_2-策略梯度方法可以学习随机策略" aria-label="Permalink to “2. 策略梯度方法可以学习随机策略”">​</a></h4><p>策略梯度方法可以 <strong>学习随机策略，而价值函数则不能</strong>。</p><p>这有两个好处：</p><ol><li><p>我们<strong>不需要手动实现探索/开发平衡</strong>。由于我们输出动作的概率分布，因此智能体通过采样探索<strong>状态空间而不总是采用相同的轨迹。</strong></p></li><li><p>我们摆脱了<strong>感知混叠</strong> 的问题。感知混叠是指两个状态看起来（或确实）相同但需要采取不同的动作。</p></li></ol><h4 id="_3-策略梯度算法在高维动作空间和连续动作空间更有效" tabindex="-1">3. 策略梯度算法<strong>在高维动作空间和连续动作空间更有效</strong>. <a class="header-anchor" href="#_3-策略梯度算法在高维动作空间和连续动作空间更有效" aria-label="Permalink to “3. 策略梯度算法在高维动作空间和连续动作空间更有效.”">​</a></h4><p>Deep Q learning 的问题在于，在给定当前状态的情况下， DQN 会在每个时间步为每个可能的动作分配一个分数（最大未来期望奖励） 。但是，如果我们有无限可能的动作呢？</p><p>例如，对于自动驾驶汽车，在每个状态下都可以（几乎）无限地选择动作（将方向盘转动 15 °、17.2 °、19.4 °、鸣喇叭等）。我们需要为每个可能的动作输出一个 Q 值！而采取连续输出的最大动作本身就是一个优化问题！</p><p>相反，使用策略梯度，我们输出的是<strong>动作的概率分布，而无需担心这一问题。</strong></p><h4 id="_4-策略梯度方法具有更好的收敛性" tabindex="-1">4. 策略梯度方法具有更好的收敛性 <a class="header-anchor" href="#_4-策略梯度方法具有更好的收敛性" aria-label="Permalink to “4. 策略梯度方法具有更好的收敛性”">​</a></h4><p>在基于价值的方法中，我们使用激进的运算方法来<strong>改变价值函数：我们在 Q 估计上取最大值</strong>。因此，对于估计动作值的任意小变化，如果该变化导致具有最大值的不同动作，动作概率可能会发生显着变化。</p><p>例如，如果在训练期间，最好的动作是左边的（Q 值为 0.22），而在它之后的训练步骤是右边的（因为右边的 Q 值变为 0.23），我们极大地改变了策略，因为现在策略将大部分时间都是靠右而不是靠左。</p><p>另一方面，在策略梯度方法中，随机策略行动偏好（采取行动的概率）<strong>随时间平稳变化</strong>。</p><h3 id="策略梯度方法的缺点" tabindex="-1">策略梯度方法的缺点 <a class="header-anchor" href="#策略梯度方法的缺点" aria-label="Permalink to “策略梯度方法的缺点”">​</a></h3><p>当然， Policy Gradient 方法也有缺点：</p><ul><li><strong>策略梯度在很多时候收敛于局部最大值而不是全局最优值。</strong></li><li>策略梯度算法的训练需要更长的时间才能收敛（效率低下）。</li><li>策略梯度可能具有高方差（解决方案： 基线方法）。</li></ul><h2 id="策略梯度方法" tabindex="-1">策略梯度方法 <a class="header-anchor" href="#策略梯度方法" aria-label="Permalink to “策略梯度方法”">​</a></h2><p>Policy-Gradient 是 Policy-Based Methods 的一个子类，<strong>旨在直接优化策略，而不使用价值函数</strong>。与基于策略的方法的不同之处在于，策略梯度方法是一系列旨在 <strong>通过使用梯度上升估计最优策略的权重来直接优化策略的算法。</strong></p><h3 id="策略梯度概述" tabindex="-1">策略梯度概述 <a class="header-anchor" href="#策略梯度概述" aria-label="Permalink to “策略梯度概述”">​</a></h3><p>强化学习旨在 <strong>找到最佳行为策略（策略）以最大化其期望累积奖励。</strong></p><p>策略是<strong>给定状态、输出动作分布</strong> 的函数（在我们的例子中使用随机策略）。</p><img src="https://huggingface.co/blog/assets/63_deep_rl_intro/pbm_2.jpg" alt="随机策略" style="zoom:25%;"><p>我们以 CartPole-v1 为例：</p><ul><li>输入一个状态 $S_t$, 输出该状态下动作的概率分布。</li></ul><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/policy_based.png" alt="基于策略" style="zoom:25%;"><p>我们使用策略梯度的目标是通过调整策略来<strong>控制动作的概率分布，以便在未来更频繁地对好的动作（最大化回报）进行采样。</strong> 每次智能体与环境交互时，我们都会调整参数，以便将来更有可能对好的动作进行采样。</p><p>但是<strong>我们如何使用期望回报来优化权重</strong>呢？</p><p>我们的想法是<strong>让智能体在一局中进行交互</strong>。如果我们赢得了这一局，我们认为所采取的每项行动都是好的，并且在未来必须进行更多的采样，因为它们会导致获胜。所以对于每个状态-动作对，我们想增加 $P( a ｜s )$：在那个状态下采取那个动作的概率。如果我们输了，则减少这个值。</p><p>策略梯度算法（简化）如下所示：</p><img src="https://huggingface.co/blog/assets/85_policy_gradient/pg_bigpicture.jpg" alt="策略梯度大图" style="zoom:25%;"><p>现在我们了解了全局，让我们更深入地研究策略梯度方法。</p><h3 id="深入研究策略梯度方法" tabindex="-1">深入研究策略梯度方法 <a class="header-anchor" href="#深入研究策略梯度方法" aria-label="Permalink to “深入研究策略梯度方法”">​</a></h3><p>我们的策略函数 $π$, 参数为 θ。给定一个状态，这个 $π$ <strong>输出该状态下采取动作的概率分布</strong>。</p><img src="https://huggingface.co/blog/assets/85_policy_gradient/policy.jpg" alt="Policy" style="zoom:25%;"><p>其中，$\\pi_\\theta(a_t|s_t)$ 是根据我们的策略，智能体从状态 $s_t$ 选择动作的概率。</p><p><strong>我们怎么知道我们的 Policy 是否好呢？</strong> 需要有一种方法来衡量它。我们定义一个得分/目标函数，称为 $J(θ)$.</p><h3 id="目标函数" tabindex="-1">目标函数 <a class="header-anchor" href="#目标函数" aria-label="Permalink to “目标函数”">​</a></h3><p>目标函数为我们提供了给定轨迹<strong>的智能体的性能</strong>（不考虑奖励的状态动作序列（与情节相反）），并输出期望的累积奖励。</p><img src="https://huggingface.co/blog/assets/85_policy_gradient/objective.jpg" alt="返回" style="zoom:25%;"><p>让我们详细地说明这个公式：</p><ul><li><em>期望回报</em>（也称为期望累积奖励）是所有 $R( τ )$ 可以采取的可能值的加权平均（其中权重由 $P(τ ;θ)$ 给出）。</li></ul><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/expected_reward.png" alt="返回" style="zoom:25%;"><ul><li>$R(τ)$：任意轨迹的回报。要获取这个值并用它来计算期望回报，我们需要将它乘以每个可能轨迹的概率。</li><li>$P(τ ;θ)$ ：每个可能轨迹τ的概率（这个概率取决于<em>θ</em>因为它定义了它用来选择轨迹动作的策略，作为访问状态的影响）。</li></ul><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/probability.png" alt="可能性" style="zoom:25%;"><ul><li>$J(θ)$：期望回报，我们通过对所有轨迹求和来计算，在给定<em>θ</em>情况下采用给定的轨迹的概率，以及这条轨迹的回报。</li></ul><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/max_objective.png" alt="最大物镜" style="zoom:25%;"><h3 id="梯度上升和策略梯度定理" tabindex="-1">梯度上升和策略梯度定理 <a class="header-anchor" href="#梯度上升和策略梯度定理" aria-label="Permalink to “梯度上升和策略梯度定理”">​</a></h3><p>策略梯度是一个优化问题：所以我们必须找到最佳参数 (θ) 来最大化我们的目标函数 $J(θ)$，我们需要使用<strong>梯度上升</strong>，(与梯度下降相反，给出了 $J(θ)$ 最陡峭增加的方向).</p><p>我们对梯度上升的更新步骤是：</p><p>$$ θ←θ+α*∇_θ*J(θ) $$ 我们可以重复应用这个更新公式，希望 <em>θ</em> 收敛到最大化 $J(θ)$ 的值。</p><p>然而，要获得 $J(θ)$ 的导数， 有两个主要问题：</p><ol><li>我们无法计算目标函数的真实梯度，因为这意味着计算每个可能轨迹的概率，这在计算上非常昂贵。我们想<strong>用基于样本的估计（收集一些轨迹）来计算梯度估计</strong>。</li><li>我们还有另一个问题，我将在下一个可选部分中详细说明。为了区分这个目标函数，我们需要区分状态分布，称为马尔可夫决策过程动力学。这是依附于环境的。在给定当前状态和智能体采取的操作的情况下，它为我们提供了环境进入下一个状态的概率。问题是我们无法区分它，因为我们可能不知道它。</li></ol><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/probability.png" alt="Probability" style="zoom:25%;"><p>幸运的是，我们将使用称为策略梯度定理的解决方案，它将帮助我们将目标函数重新表述为一个不涉及状态分布微分的可微分函数。</p><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/policy_gradient_theorem.png" alt="策略梯度" style="zoom:25%;"><h3 id="reinforce-算法-monte-carlo-reinforce" tabindex="-1">Reinforce 算法（Monte Carlo Reinforce） <a class="header-anchor" href="#reinforce-算法-monte-carlo-reinforce" aria-label="Permalink to “Reinforce 算法（Monte Carlo Reinforce）”">​</a></h3><p>Reinforce，也称为 Monte-Carlo Policy Gradient，是一种策略梯度算法， <strong>使用整个 episode 的估计回报来更新策略参数</strong> $θ$. 我们的策略函数 $π$，它有一个参数 θ。给定一个状态，这个 $π$ <strong>输出该状态下采取动作的概率分布</strong>。</p><p>Reinforce 算法的工作原理如下：</p><p>在一个循环中：</p><ul><li><p>使用策略 $π_θ$ 收集智能体的轨迹 $τ $</p></li><li><p>使用 episode 的数据来估计梯度 $\\hat{g} = \\nabla_\\theta J(\\theta)$</p><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/policy_gradient_one.png" alt="策略梯度" style="zoom:25%;"></li><li><p>更新策略的权重：$\\theta \\leftarrow \\theta + \\alpha \\hat{g}$</p></li></ul><p>我们可以做出的解释是：</p><ul><li>$\\nabla_\\theta logπ_θ(a_t∣s_t)$ 是从状态 $s_{t}$ 选择动作<strong>的（对数）概率最陡增</strong>的方向。这告诉我们如果我们想增加/减少在在状态 $s_{t}$ 选择动作 $a_{t}$ 的对数概率，我们应该如何改变策略的权重。</li><li>$R (\\tau)$: 是评分函数：</li><li>如果回报很高，它会<strong>推高</strong>（状态，动作）组合的概率。</li><li>否则，如果回报很低，它会<strong>降低</strong>（状态，动作）组合的概率。</li></ul><p>我们还可以<strong>收集多个片段（轨迹）</strong>来估计梯度：</p><img src="https://huggingface.co/datasets/huggingface-deep-rl-course/course-images/resolve/main/en/unit6/policy_gradient_multiple.png" alt="策略梯度" style="zoom:25%;"><p>举一个简单的例子：</p><ul><li>我们通过 Policy 与环境互动来收集经验。</li><li>然后我们查看 Episode 的奖励总和（期望回报）。如果这个总和是正的，我们 <strong>认为在这些经验中采取的行动是好的：</strong>因此，我们想要增加每个<code>状态-行动对</code>的 $P(a|s)$（在该状态下采取该行动的概率）。如果这个总和是负的，我们则减少每个<code>状态-行动</code>对的 $P(a|s)$</li></ul><h2 id="补充阅读" tabindex="-1">补充阅读 <a class="header-anchor" href="#补充阅读" aria-label="Permalink to “补充阅读”">​</a></h2><h3 id="introduction-to-policy-optimization" tabindex="-1">Introduction to Policy Optimization <a class="header-anchor" href="#introduction-to-policy-optimization" aria-label="Permalink to “Introduction to Policy Optimization”">​</a></h3><ul><li><a href="https://spinningup.openai.com/en/latest/spinningup/rl_intro3.html" target="_blank" rel="noreferrer">Part 3: Intro to Policy Optimization - Spinning Up documentation</a></li></ul><h3 id="policy-gradient-1" tabindex="-1">Policy Gradient <a class="header-anchor" href="#policy-gradient-1" aria-label="Permalink to “Policy Gradient”">​</a></h3><ul><li><a href="https://johnwlambert.github.io/policy-gradients/" target="_blank" rel="noreferrer">https://johnwlambert.github.io/policy-gradients/</a></li><li><a href="https://jonathan-hui.medium.com/rl-policy-gradients-explained-9b13b688b146" target="_blank" rel="noreferrer">RL - Policy Gradient Explained</a></li><li><a href="http://incompleteideas.net/book/RLbook2020.pdf" target="_blank" rel="noreferrer">Chapter 13, Policy Gradient Methods; Reinforcement Learning, an introduction by Richard Sutton and Andrew G. Barto</a></li></ul><h3 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to “Implementation”">​</a></h3><ul><li><a href="https://github.com/PyTorch/examples/blob/main/reinforcement_learning/reinforce.py" target="_blank" rel="noreferrer">PyTorch Reinforce implementation</a></li><li><a href="https://github.com/MrSyee/pg-is-all-you-need" target="_blank" rel="noreferrer">Implementations from DDPG to PPO</a></li></ul>',98)])])}const m=a(o,[["render",l]]);export{d as __pageData,m as default};
